{% comment %} Detect if this is a shoe product {% endcomment %}
{% assign is_shoe = false %}
{% if product %}
  {% assign product_type_lower = product.type | downcase %}
  {% for tag in product.tags %}
    {% assign tag_lower = tag | downcase %}
    {% if tag_lower contains 'shoe' or tag_lower contains 'boot' or tag_lower contains 'sandal' or tag_lower contains 'sneaker' %}
      {% assign is_shoe = true %}
      {% break %}
    {% endif %}
  {% endfor %}
  {% if product_type_lower contains 'shoe' or product_type_lower contains 'footwear' %}
    {% assign is_shoe = true %}
  {% endif %}
{% endif %}

{% if collection %}
  {% assign collection_handle_lower = collection.handle | downcase %}
  {% if collection_handle_lower contains 'shoe' %}
    {% assign is_shoe = true %}
  {% endif %}
{% endif %}

{% unless is_shoe %}
