<style>
  .oc_cu_icons {
    --colorBody: #ffffff;
    --colorTextBody: #1c1d1d;
    --colorBorder: #e8e8e1;
    --typeHeaderPrimary: "ITC Avant Garde Gothic";
    --typeHeaderFallback: sans-serif;
    --typeHeaderWeight: 700;
    --typeHeaderLineHeight: 1.2;
    --typeHeaderSpacing: 0.0em;
    --typeBasePrimary: Futura;
    --typeBaseFallback: sans-serif;
    --typeBaseSize: 15px;
    --typeBaseWeight: 400;
    --typeBaseLineHeight: 1.6;
    --typeBaseSpacing: 0.025em;
  }

  .oc_cu_icons {
    background-color: var(--colorBody);
    padding: 0px;
    margin-top: -30px;
    margin-bottom: -30px;
  }

  .oc_cu_icons .page-width {
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 20px;
  }

  .oc_cu_icons .oc_icons_wrap {
    display: flex;
    flex-wrap: wrap;
    margin: 0 -15px;
  }

  .oc_cu_icons .grid {
    display: flex;
    flex-wrap: wrap;
  }

  .oc_cu_icons .grid--uniform {
    align-items: stretch;
  }

  .oc_cu_icons .grid--flush-bottom {
    margin-bottom: 0;
  }

  .oc_cu_icons .grid__item {
    padding: 0 15px;
    margin-bottom: 40px;
  }

  .oc_cu_icons .oc_icons_item {
    display: flex;
    flex-direction: row;
    align-items: flex-start;
    text-align: left;
    gap: 20px;
  }

  .oc_cu_icons .medium-up--one-quarter {
    flex: 0 0 100%;
    max-width: 100%;
  }

  @media (min-width: 768px) {
    .oc_cu_icons .medium-up--one-quarter {
      flex: 0 0 50%;
      max-width: 50%;
    }
  }

  @media (min-width: 1024px) {
    .oc_cu_icons .medium-up--one-quarter {
      flex: 0 0 25%;
      max-width: 25%;
    }
  }

  .oc_cu_icons .oc_img_icons {
    display: flex;
    align-items: flex-start;
    justify-content: flex-start;
    flex-shrink: 0;
    padding-top: 2px;
  }

  .oc_cu_icons .oc_img_icons img,
  .oc_cu_icons .oc_img_icons svg {
    width: 68px;
    height: 68px;
    object-fit: contain;
    border-radius: 8px;
    transition: transform 0.3s ease;
    display: block;
  }

  .oc_cu_icons .oc_icons_content {
    flex: 1;
    min-width: 0;
  }

  .oc_cu_icons .oc_icons_content h5 {
    font-family: var(--typeHeaderPrimary), var(--typeHeaderFallback);
    font-size: 1.1rem;
    font-weight: var(--typeHeaderWeight);
    color: var(--colorTextBody);
    margin: 0 0 10px 0;
    line-height: var(--typeHeaderLineHeight);
    letter-spacing: var(--typeHeaderSpacing);
  }

  .oc_cu_icons .rte-setting {
    font-family: var(--typeBasePrimary), var(--typeBaseFallback);
    font-size: var(--typeBaseSize);
    font-weight: var(--typeBaseWeight);
    line-height: var(--typeBaseLineHeight);
    color: var(--colorTextBody);
    letter-spacing: var(--typeBaseSpacing);
  }

  .oc_cu_icons .text-spacing p {
    margin: 0;
  }

  .oc_cu_icons .text-left {
    text-align: left;
  }

  /* Mobile adjustments */
  @media (max-width: 767px) {
    .oc_cu_icons {
      padding: 20px 0;
    }

    .oc_cu_icons .page-width {
      padding: 0 15px;
    }

    .oc_cu_icons .oc_icons_wrap {
      margin: 0 -10px;
    }

    .oc_cu_icons .grid__item {
      padding: 0 10px;
      margin-bottom: 30px;
    }

    .oc_cu_icons .oc_icons_item {
      gap: 15px;
    }

    .oc_cu_icons .oc_icons_content h5 {
      font-size: 1rem;
    }

    .oc_cu_icons .rte-setting {
      font-size: 14px;
    }
  }

  @media (max-width: 480px) {
    .oc_cu_icons .oc_icons_item {
      gap: 12px;
    }

    .oc_cu_icons .oc_icons_content h5 {
      font-size: 0.95rem;
      line-height: 1.4;
    }

    .oc_cu_icons .rte-setting {
      font-size: 13px;
    }

    .oc_cu_icons .oc_img_icons img,
    .oc_cu_icons .oc_img_icons svg {
      width: 60px;
      height: 60px;
    }
  }

  /* Hover effects */
  .oc_cu_icons .oc_icons_item {
    transition: transform 0.3s ease;
  }

  .oc_cu_icons .oc_icons_item:hover {
    transform: translateY(-2px);
  }

  .oc_cu_icons .oc_icons_item:hover .oc_img_icons img,
  .oc_cu_icons .oc_icons_item:hover .oc_img_icons svg {
    transform: scale(1.05);
  }

  /* Fix for SVG visibility on load */
  .oc_cu_icons svg {
    visibility: visible !important;
    opacity: 1 !important;
  }
</style>
